@page "/Account/Login"
@layout sv_2d6178f7ac2b47e282a7b405a2fdc024.Components.Layout.MainLayout
@using Microsoft.AspNetCore.Identity
@using sv_2d6178f7ac2b47e282a7b405a2fdc024.Data
@inject SignInManager<ApplicationUser> SignInManager
@inject NavigationManager Navigation

<PageTitle>Login</PageTitle>

<div class="row justify-content-center mt-5">
    <div class="col-md-4">
        <h3>Login</h3>
        @if (!string.IsNullOrEmpty(errorMessage))
        {
            <div class="alert alert-danger">@errorMessage</div>
        }
        <form method="post" @formname="login">
            <AntiforgeryToken />
            <div class="mb-3">
                <label class="form-label">Email</label>
                <input type="email" name="Email" class="form-control" @bind="email" required />
            </div>
            <div class="mb-3">
                <label class="form-label">Password</label>
                <input type="password" name="Password" class="form-control" @bind="password" required />
            </div>
            <button type="submit" class="btn btn-primary w-100">Log in</button>
        </form>
    </div>
</div>

@code {
    [SupplyParameterFromForm] private string email { get; set; } = "";
    [SupplyParameterFromForm] private string password { get; set; } = "";
    [SupplyParameterFromQuery] private string? returnUrl { get; set; }
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        if (HttpMethods.IsPost(httpContext.Request.Method))
        {
            var result = await SignInManager.PasswordSignInAsync(email, password, isPersistent: false, lockoutOnFailure: false);
            if (result.Succeeded)
            {
                Navigation.NavigateTo(returnUrl ?? "/", forceLoad: true);
            }
            else
            {
                errorMessage = "Invalid email or password.";
            }
        }
    }

    [CascadingParameter] private HttpContext httpContext { get; set; } = default!;
}

